class AllOne {
    private Map<String, Integer> counts;
    private Map<Integer, Set<String>> countToKeys;
    private int maxCount;
    private int minCount;

    public AllOne() {
        counts = new HashMap<>();
        countToKeys = new HashMap<>();
        maxCount = 0;
        minCount = 0;
    }

    public void inc(String key) {
        int count = counts.getOrDefault(key, 0) + 1;
        counts.put(key, count);
        countToKeys.computeIfAbsent(count, k -> new HashSet<>()).add(key);
        if (count > maxCount) {
            maxCount = count;
        }
        if (count < minCount || minCount == 0) {
            minCount = count;
        }
    }

    public void dec(String key) {
        int count = counts.get(key) - 1;
        counts.put(key, count);
        countToKeys.get(counts.get(key)).remove(key);
        if (count < minCount) {
            minCount = count;
        }
        if (count == 0) {
            counts.remove(key);
        }
    }

    public String getMaxKey() {
        if (maxCount == 0) {
            return "";
        }
        Set<String> keys = countToKeys.get(maxCount);
        return keys.iterator().next();
    }

    public String getMinKey() {
        if (minCount == 0) {
            return "";
        }
        Set<String> keys = countToKeys.get(minCount);
        return keys.iterator().next();
    }
}
